System.register(["./index-legacy-B7IS58LZ.js"],function(t,e){"use strict";var n,i,s,c,l,o,r,a,u,p;return{setters:[function(t){n=t.d,i=t.c,s=t.a,c=t.u,l=t.F,o=t.f,r=t.k,a=t.l,u=t.t,p=t.b}],execute:function(){var e={class:"min-h-screen px-4 py-8 flex justify-center"},d={class:"game-panel w-full max-w-4xl space-y-6"},x={class:"flex items-center justify-between"},f={class:"border border-accent/20 rounded-xs p-4 space-y-2"},V={class:"flex flex-wrap gap-2 mt-3"},m=["onClick"],b=["id"],y={class:"text-accent text-lg"},v={class:"text-sm text-muted leading-relaxed"},C={key:0,class:"text-xs text-muted space-y-1 list-disc list-inside"};t("default",n({__name:"TutorialView",setup:function(t){var n=r(),k=[{title:"第一天：安家落户",content:"进入游戏后，柳村长会迎接你来到桃源乡。你的背包里已经有白菜种子，第一件事就是去农场开垦土地。点击底部导航栏的「农场」按钮，在农场面板中点击「一键操作」→「一键开垦」，然后用「一键种植」把白菜种子播下去。之后记得「一键浇水」——作物不浇水是不会生长的。体力是有限的，合理安排每天的行动很重要。体力不足时可以吃东西补充，或者直接去家里睡觉结束一天。",tips:["每天体力 = 基础100 + 工具加成 + 食物加成","睡觉会结束当天，所有未完成的操作会丢失进度","凌晨2点不睡觉会被强制送回家并罚款"]},{title:"种田与收获",content:"作物从播种到成熟需要经过几个阶段，每个季节适合种的作物不同。春天可以种白菜、土豆、草莓等，夏天种西瓜、辣椒、蓝莓，秋天种南瓜、玉米、茄子，冬天大部分作物无法生长。成熟后的作物点击「一键收获」即可收入背包。收获物放进农场面板底部的「出货箱」，第二天就能在门口收到卖出的金币。",tips:["金色地块 = 已成熟可收获","不同作物生长天数不同，白菜3天，草莓8天但能多次收获","下雨天作物自动浇水，省体力","使用肥料可以加快生长速度"]},{title:"赚钱途径与每日签到",content:"游戏中有多种赚钱方式：① 种田卖作物——最基础的收入来源；② 钓鱼——村东清溪可以钓鱼，不同鱼类价值不同；③ 采矿——村北矿洞挖矿，矿石可以卖钱或用于打造工具；④ 完成告示栏任务——乡亲们的委托，完成后有金币奖励；⑤ 参加节日活动——钓鱼大赛、丰收展览等活动有丰厚奖励。地图里的「每日签到」按现实北京时间刷新，连续签到会逐步提高铜钱奖励，并赠送种子、肥料等实用物品。",tips:["签到奖励会直接进入当前角色：铜钱进钱袋，物品进背包","连续签到按7天循环，后续会继续扩展稀有材料奖励","升级工具（水壶、锄头、鱼竿等）能提高效率","铁匠铺可以打造和升级装备"]},{title:"社交与NPC",content:"桃源乡有很多NPC可以互动。去「村庄」面板可以查看所有NPC，和NPC聊天、送礼可以提升好感度。好感度达到一定等级会触发心形事件，解锁特殊剧情。每个NPC有不同的喜好物品，送喜欢的礼物好感度加成更多。每周可以送礼两次。",tips:["NPC生日当天送礼效果翻倍","完成NPC的委托任务也能提升好感","好感度8心以上可以结婚（部分NPC）"]},{title:"加工与制作",content:"加工坊可以把原材料加工成更有价值的成品，比如牛奶→奶酪，矿石→金属锭，木材→木板等。厨房可以做各种料理，吃了能恢复体力和增加临时buff。铁匠铺可以打造工具、武器，还能升级装备品质。",tips:["制作洒水器可以自动浇水","食谱可以通过提升技能等级或购买获得","装备有不同的稀有度：白→绿→蓝→紫→橙"]},{title:"养殖与宠物",content:"可以在商铺建造鸡舍、牧场等养殖建筑。鸡舍养鸡和鸭，牧场养牛和羊。每天给动物喂食、抚摸可以获得产出（鸡蛋、牛奶、羊毛等）。心数越高的动物产出品质越好。鱼塘可以养鱼，放一条鱼进去慢慢繁殖。",tips:["冬天动物需要取暖器，否则不开心","动物产出可以在加工坊进一步加工","灵兽系统在修仙玩法中解锁"]},{title:"修仙系统",content:"修仙是桃源乡的特色玩法，解锁后可以修炼提升境界。境界从低到高：凡人→练气→筑基→金丹→元婴→化神→渡劫→大乘。修炼需要灵气，可以通过灵田种植灵植、炼丹等方式获取。加入宗门后，不只是学习技能，还可以完成每日宗门日课、积累贡献和功勋、晋升职位、在宗门宝库兑换灵石/灵植种子/秘境材料。法宝系统让你可以装备6个法宝，提升战斗力和修炼效率。",tips:["每日修炼可以获得大量灵气","灵植炼丹是提升灵气的主要途径","三个宗门各有特色，选择适合自己的","筑基后优先做宗门日课，职位越高技能上限和日课收益越好"]},{title:"从种田开始修仙",content:"修仙不再是突然打开的新系统。前期先正常翻土、播种、收获，作物收获会逐步积累「地脉感应」；地脉感应达到100后，去地图的「修仙之途」→「修行」花费铜钱启蒙灵田。启蒙后，普通作物也会转化少量灵气，蕴灵稻、凝露草、朱果等灵植则能提供更多灵气并作为炼丹材料。",tips:["推荐路线：种田收获 → 地脉感应100 → 启蒙灵田 → 灵膳修行/炼丹突破","温室收获也会触发地脉感应和灵气收益","普通作物可做灵谷粥，灵植可做更高阶灵膳","特殊订单会出现宗门灵植单，提交灵植可换灵石、种子和秘境材料"]},{title:"修行志与每日目标",content:"任务页新增「修行志」，会把早期路线拆成可领取奖励的小目标：先收获作物、积累地脉感应，再启蒙灵田、突破炼气，并通过委托和战斗补上每日成长。修行志分为主线引导、每日修行和七日目标，完成后可领取铜钱、灵气和角色资质经验。",tips:["不知道下一步做什么时，先打开「任务」查看修行志","主线引导负责串起种田到修仙，每日修行负责上线目标，七日目标负责前期节奏","奖励不会自动发放，需要在修行志中点击「领取」"]},{title:"角色属性成长",content:"角色信息页新增「角色资质」：根骨、力道、身法、悟性。收获作物会提升根骨和悟性，优质作物给更多悟性；矿洞战斗、红尘历练和挑战凶兽会提升力道与身法。属性会保存到账号角色存档中，并实际影响生命、攻击和减伤。",tips:["想稳步变强，日常种田和战斗都要做","根骨偏生存，力道偏攻击，身法偏减伤，悟性代表修行理解","角色页可查看每项属性等级和下一次成长进度"]},{title:"像素田庄与灵田外观",content:"农场地块、种子、作物和角色信息页已改成更接近图片素材的像素化表现。每类种子都有不同的像素种袋和颗粒形状，作物会按幼苗、生长、成熟呈现不同色块轮廓；启蒙灵田后，田地会随灵田等阶出现不同灵光网格、边框和光效。",tips:["普通田、黄阶、玄阶、地阶、天阶灵田都有不同视觉层次","不同作物会按叶菜、根茎、谷物、瓜果、花草、灵植等类别显示不同像素素材色板","角色页的小人会根据性别和修行境界显示不同衣装与光环"]},{title:"账号角色与继续游戏",content:"桃源乡现在以账号角色作为正式存档入口。先在首页登录或注册账号，再点击「踏入旅途」创建角色；已有角色会显示在首页「账号角色」列表中，点击对应角色的「继续游戏」即可进入。每个账号最多创建3个角色，角色名全服唯一。浏览器本地数据只作为运行缓存，正式角色和进度以服务器数据库为准。",tips:["首页「账号角色」会显示当前账号已有角色和数量上限","想切换角色时回到首页，点击另一个角色的「继续游戏」","不要把浏览器缓存当成正式存档，登录账号后的数据库进度才是正式数据"]},{title:"V0.5：红尘历练与挑战凶兽",content:"V0.5把原来的「秘境」扩展成三类玩法：红尘历练、挑战凶兽、秘境探索。入口仍在地图的「修仙之途」→「秘境」。修行志里的「初战妖兽」完成条件是任意一次战斗胜利，新手可先选择红尘历练或登仙塔低层，不必一开始就挑战高门槛凶兽。红尘历练是主线成长玩法，会随着转生次数逐步开放桃源山径、青丘旧林、云梦泽、昆仑外境等区域；挑战凶兽每天限次，可获得真灵秘录、轮回尘、灵蕴玉等转生核心材料；秘境探索继续承担炼器、灵石和基础材料产出。",tips:["初战妖兽：地图 → 修仙之途 → 秘境，打赢任意一场即可完成","新手优先选择红尘历练或登仙塔低层，强度比凶兽更平滑","凶兽挑战有每日次数限制，建议境界和转生达标后再打","1转后开放青丘旧林，3转后开放云梦泽，8转后开放昆仑外境"]},{title:"V1.0：天劫渡劫与挂机修仙",content:"V1.0后，修仙成长更完整：在线时会持续挂机吐纳，离线回归也能获得灵气、修为和部分元神经验。小境界突破更顺滑，跨越大境界时才会触发天劫/渡劫；渡劫前页面会显示成功率，失败会损失部分灵气、修为、灵力，并造成元神伤势。可通过炼制或使用养魂丹、涅魂丹恢复元神状态。",tips:["入口：地图 → 修仙之途 → 修行","突破大境界前先准备足够灵气、灵力和恢复丹药","在线挂机和离线回归都会给修仙资源，适合长期养成"]},{title:"V1.0.1：功法与修仙市集",content:"修仙市集新增灵石购买内容：纳物符和乾坤袋可永久增加背包容量，并且能突破普通扩容上限；青木长生诀、九霄雷诀、太虚归元功三类功法秘籍可购买后在背包使用学习。学会功法后，去修行页面升级功法层数，消耗灵气和修为，获得修炼收益、战力、灵力、渡劫成功率等加成。",tips:["入口：地图 → 修仙之途 → 修仙市集，可用灵石购买","秘籍买到后要去背包点击使用，才会学习功法","背包容量道具也在背包中使用，纳物符+1，乾坤袋+4"]},{title:"V1.1：仙途七线补全",content:"任务页的修行志新增七条长期目标，把修仙主线、装备套装、深层秘境、仙盟互助、活动妖潮、新手变强引导和回访福利串起来。玩家不知道下一步做什么时，优先打开任务页查看修行志，按目标领取铜钱、灵气、修为相关成长奖励。",tips:["入口：地图 → 修仙之途 → 限时活动；也可在底部导航 → 任务 → 修行志查看","七线目标会引导你修境界、练功法、打秘境、做委托和击败怪物","回访福利进游戏后即可领取一次，适合老玩家回来追进度"]},{title:"V1.3.6：怪物像素素材风格化",content:"战斗中所有怪物和BOSS不再使用通用表情/emoji图标，改为与怪物名字风格匹配的中国色系像素素材。灵狼灰蓝铁色、灵熊深棕厚甲、青丘灵狐橙黄赤金、冥蛛暗紫红眼、饕餮赤金巨爪、混沌暗灰紫光……每种怪物拥有独特的体色、眼光、爪色和灵气光环，像名字一样有辨识度。",tips:["灵狼：灰蓝铁色体，赤金眼光","灵熊：深棕厚重，赤金利爪","青丘灵狐：橙黄赤金，灵气外溢","冥蛛：暗紫体+朱红眼","饕餮/穷奇：赤金巨爪+灵蕴光环","混沌：暗灰紫光，神秘深邃","登仙塔怪物各有独特金属/暗影/烈焰/灵光风格"]},{title:"V1.3.5：修行流派与心境称号",content:"修行页新增修行流派与心境称号，可在清修、剑修、丹修、雷修之间切换。清修偏稳定打坐与压制心魔，剑修偏战力与周天运转，丹修偏炼化灵气与灵植丹药循环，雷修偏雷云观想、顿悟和渡劫稳定性。流派不会新增入口，而是强化已有修行、课业、闭关和渡劫。",tips:["心魔高或想稳扎稳打可选清修","主打秘境/登仙塔可选剑修","种田炼丹循环可选丹修","准备大境界渡劫可选雷修","流派可随时切换，根据当天目标调整"]},{title:"V1.3.4：修行瓶颈与心魔",content:"修行页新增顿悟与心魔。闭关参悟会消耗体力和灵力，积累顿悟并削减心魔；顿悟能提高大境界渡劫稳定性，心魔会压低成功率。渡劫失败会积累心魔并折损顿悟，突破成功则会缓解心魔，让突破前的准备更有修仙味。",tips:["大境界突破前先闭关参悟，能提高渡劫稳定性","心魔过高时不要硬渡劫，先闭关或恢复元神","小层突破会消耗少量顿悟并降低心魔","太虚归元功和元神等级能帮助闭关压制心魔"]},{title:"V1.3.3：修行纵深第一期",content:"修行页新增每日修行课业，不增加新入口，只在原有灵田修行中强化每日选择。纳气晨课适合稳修，周天运转适合冲修为，雷云观想适合渡劫前准备并积累元神经验。课业每日每门一次，会消耗体力或材料，并受灵田、功法、境界影响。",tips:["刚启蒙优先纳气晨课，收益稳定","需要快速突破小境界时选周天运转","大境界渡劫前准备雷云观想","雷云观想需要雷精，可通过秘境/宗门等玩法补充"]},{title:"V1.3.2：宗门差异与专属委派",content:"三大宗门开始有更明确的玩法差异。剑宗偏战斗，宗门技能会额外提升战力，并可每日完成「剑冢试剑」获得星陨铁和灵石；丹宗偏种田炼丹循环，可完成「丹房看炉」，消耗凝露草换取灵植种子；符宗偏防御和符阵，可完成「符阵巡检」，消耗灵石换取魂晶和木灵珠。宗门功勋、职位、技能现在也会更明确地进入战力估算。",tips:["剑宗适合主打秘境、登仙塔和战斗成长","丹宗适合灵植、炼丹、订单循环","符宗适合稳健防御和符阵资源","宗门专属委派每日一次，和普通日课共用每日重置"]},{title:"V1.3.1：宗门纵深第一期",content:"宗门系统从单纯选门派和升级技能，扩展为职位、日课、贡献、功勋和宝库循环。加入宗门后每天可完成听道早课、山门巡守、上交灵材，获得贡献与功勋；功勋和境界达标后可从外门弟子晋升到内门、亲传、执事、长老候补。职位提升会提高技能等级上限和日课收益，贡献可用于升级宗门技能或在宝库兑换灵石、灵植种子、秘境材料。",tips:["入口：地图 → 修仙之途 → 宗门","筑基后可加入剑宗、丹宗、符宗","先做每日宗门日课，再考虑升级技能或兑换宝库","职位晋升需要功勋、境界和贡献，属于长期目标"]},{title:"V1.3：玩法内容纵深第一期",content:"从V1.3开始，更新重点转向深耕已有玩法。特殊订单会混入「宗门灵植」订单，要求提交蕴灵稻、凝露草、朱果、雪莲等灵植，奖励灵石、灵植种子、木灵珠、魂晶、雷精等修仙/秘境资源。这样种田不只是卖钱，而会进入“种灵植 → 交宗门订单 → 获得修仙材料 → 炼丹/秘境/再种田”的循环。特殊订单提交时会正式扣除目标物品，请提前留好库存。",tips:["入口：任务 → 特殊订单，季末梯度订单更容易刷到高阶需求","蕴灵稻、凝露草、朱果是早期灵植循环核心","雪莲订单偏后期，奖励雷精等高阶材料","以后会继续给NPC、秘境、炼丹、法宝补更多内容而不是只加新入口"]},{title:"高级玩法：秘境·炼器·排行",content:"旧版秘境已在V0.5扩展为红尘历练/挑战凶兽/秘境探索三类；早期版本新增了三大秘境（莽荒秘境、幽冥秘境、天元秘境），每个秘境有不同的怪物和掉落。炼器系统支持8种配方，打造神兵利器。排行榜展示修为、铜钱、灵气的前10名玩家，突破大境界时全服广播。",tips:["秘境每天有进入次数限制","排行榜每天更新一次","突破大境界需要满足灵气条件"]}];return function(t,r){return a(),i("div",e,[s("div",d,[s("div",x,[r[1]||(r[1]=s("h1",{class:"text-accent text-xl"},"📖 新手教程",-1)),s("button",{class:"btn text-xs",onClick:r[0]||(r[0]=function(t){return c(n).back()})},"返回")]),s("div",f,[r[2]||(r[2]=s("p",{class:"text-sm text-muted"},"欢迎来到《我从种田开始修仙》！这篇教程将引导你从零开始，逐步掌握种田、经营与修仙成长。",-1)),s("div",V,[(a(),i(l,null,o(k,function(t,e){return s("button",{key:e,class:"btn text-xs",onClick:function(t){return function(t){var e=document.getElementById("sec-".concat(t));e&&e.scrollIntoView({behavior:"smooth",block:"start"})}(e)}},u(e+1)+". "+u(t.title),9,m)}),64))])]),(a(),i(l,null,o(k,function(t,e){var n;return s("div",{key:e,id:"sec-".concat(e),class:"border border-accent/20 rounded-xs p-4 space-y-3"},[s("h2",y,u(e+1)+". "+u(t.title),1),s("p",v,u(t.content),1),null!==(n=t.tips)&&void 0!==n&&n.length?(a(),i("ul",C,[(a(!0),i(l,null,o(t.tips,function(t,e){return a(),i("li",{key:e},u(t),1)}),128))])):p("",!0)],8,b)}),64))])])}}}))}}});
